function SaveableCanvas({ strokeColor = "#201b3d", height = 300, lineWidth = 5, onReady }) {
  const canvasRef = useRef(null);
  const drawing = useRef(false);
  const last = useRef({ x: 0, y: 0 });

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
    if (onReady) onReady(canvas);
  }, [onReady]);

  function getPos(e) {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
  }
  function start(e) {
    drawing.current = true;
    last.current = getPos(e);
  }
  function move(e) {
    if (!drawing.current) return;
    const ctx = canvasRef.current.getContext("2d");
    const pos = getPos(e);
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = lineWidth;
    ctx.lineCap = "round";
    ctx.lineJoin = "round";
    ctx.beginPath();
    ctx.moveTo(last.current.x, last.current.y);
    ctx.lineTo(pos.x, pos.y);
    ctx.stroke();
    last.current = pos;
  }
  function end() {
    drawing.current = false;
  }
  function clear() {
    const ctx = canvasRef.current.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, canvasRef.current.width, canvasRef.current.height);
  }

  return (
    <div className="w2-canvas-wrap">
      <canvas
        ref={canvasRef}
        width={800}
        height={height * 2}
        style={{ height }}
        className="w2-canvas"
        onPointerDown={start}
        onPointerMove={move}
        onPointerUp={end}
        onPointerLeave={end}
      />
      <button className="w2-btn w2-btn-ghost" onClick={clear} type="button">
        <RotateCcw size={14} /> Clear
      </button>
    </div>
  );
}

/* A small, compact canvas used for quick one-item demo sketches
   (e.g. "draw a tiny example of Line", "draw a curved line yourself") */
function MiniCanvas({ strokeColor = "#201b3d", height = 92, lineWidth = 3.5, onDraw }) {
  const canvasRef = useRef(null);
  const drawing = useRef(false);
  const last = useRef({ x: 0, y: 0 });
  const hasDrawn = useRef(false);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
  }, []);

  function getPos(e) {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return { x: (e.clientX - rect.left) * scaleX, y: (e.clientY - rect.top) * scaleY };
  }
  function start(e) {
    drawing.current = true;
    last.current = getPos(e);
    if (!hasDrawn.current) {
      hasDrawn.current = true;
      if (onDraw) onDraw();
    }
  }
  function move(e) {
    if (!drawing.current) return;
    const ctx = canvasRef.current.getContext("2d");
    const pos = getPos(e);
    ctx.strokeStyle = strokeColor;
    ctx.lineWidth = lineWidth;
    ctx.lineCap = "round";
    ctx.lineJoin = "round";
    ctx.beginPath();
    ctx.moveTo(last.current.x, last.current.y);
    ctx.lineTo(pos.x, pos.y);
    ctx.stroke();
    last.current = pos;
  }
  function end() {
    drawing.current = false;
  }
  function clear(e) {
    e.stopPropagation();
    const ctx = canvasRef.current.getContext("2d");
    ctx.fillStyle = "#ffffff";
    ctx.fillRect(0, 0, canvasRef.current.width, canvasRef.current.height);
  }

  return (
    <div className="w2-mini-canvas-wrap">
      <canvas
        ref={canvasRef}
        width={280}
        height={height * 2}
        style={{ height }}
        className="w2-mini-canvas"
        onPointerDown={start}
        onPointerMove={move}
        onPointerUp={end}
        onPointerLeave={end}
      />
      <button className="w2-mini-clear" onClick={clear} type="button" aria-label="Clear sketch">
        <RotateCcw size={11} />
      </button>
    </div>
  );
}

